#!/usr/bin/env bash
set -euo pipefail

# LLM Attribution: Generated by Cursor (auto)

# List GitHub Actions workflow runs for a repo/workflow, optionally download artifacts,
# flatten *.xml from raw/ into REPORTS_PATH, zip them (splitting when uncompressed size exceeds
# ZIP_MAX_UNCOMPRESSED_BYTES), then delete those loose copies.
# Archive basename: REPO and WORKFLOW joined, filename-sanitized, plus the run date range.
# Requires: gh (authenticated), jq, zip; unzip when a run has multiple attempts; GNU date to
# auto-compute DATELIMIT (otherwise set DATELIMIT=YYYY-MM-DD).
# Options and environment: ./build/gather-test-reports.sh --help

usage() {
  cat <<'EOF'
Usage: gather-test-reports.sh [options]

Without options, gathers one workflow using REPO, WORKFLOW, and REPORTS_PATH (see below).

  -f, --targets FILE   Run once per line in FILE (tab-separated owner/repo and workflow
                       name). REPORTS_PATH for each row is
                       TARGETS_REPORT_BASE/<repo>/<workflow> (see TARGETS_REPORT_BASE).
                       Empty lines and lines starting with # are skipped.

  -h, --help           Show this help and exit.

Environment (defaults shown; all can be overridden):

  REPO                 GitHub repository owner/name (default: stolostron/governance-policy-framework)
  WORKFLOW             Workflow name as in the Actions UI (default: GRC Integration Test)
  REPORTS_PATH         Output directory for single-target mode, created if needed
                       (default: $PWD/$REPO/<sanitized WORKFLOW>); ignored with --targets (use
                       TARGETS_REPORT_BASE instead). Existing runs.json / raw/ / loose *.xml
                       there may be overwritten or picked up
  DATELIMIT            Only gather runs on or after this date, YYYY-MM-DD (default: 30 days ago via
                       GNU date; required manually on non-GNU systems)
  RUN_LIMIT            Max workflow runs to list, newest first (default: 300)
  DRYRUN               Set to 1, true, or yes (case insensitive) to print download commands only
                       (still writes runs.json). Unset or any other value = download artifacts and
                       flatten XML as usual.
  DOWNLOAD_DELAY_SEC   Pause between downloads (default: 1; 0 disables)
  TARGETS_REPORT_BASE  Base directory when using --targets (default: $PWD/test-output)
  ZIP_MAX_UNCOMPRESSED_BYTES  Max sum of uncompressed XML sizes per .zip (default: 25*1024*1024).
                       Set higher/lower for ReportPortal or other upload limits. A single XML larger
                       than this is placed alone in one archive (that zip may exceed the limit).

After flattening, top-level *.xml under REPORTS_PATH are zipped. Uncompressed total per archive is
at most ZIP_MAX_UNCOMPRESSED_BYTES (default 25 MiB); larger sets are split into
  <sanitized REPO_WORKFLOW>_<date-range>_partNofM.zip
If everything fits in one archive, the name is <sanitized REPO_WORKFLOW>_<date-range>.zip (no _part).
The date range is min/max run createdAt from runs.json, or DATELIMIT through today if there are no
matching runs. Loose XML copies are removed after successful zip(s). Requires zip(1) when XML files exist.
Failed artifact downloads (simple or multi-attempt) are recorded and printed in a summary block on
stderr after "Downloads complete", so they are easy to find among successful run lines.

Examples:

  DRYRUN=1 REPORTS_PATH=/tmp/reports ./build/gather-test-reports.sh
  ./build/gather-test-reports.sh -f ./build/gather-test-reports.targets
EOF
}

err() {
  echo "[$(date +'%Y-%m-%dT%H:%M:%S%z')]: $*" >&2
}

TARGETS_FILE=""
while [[ $# -gt 0 ]]; do
  case "$1" in
    -h | --help)
      usage
      exit 0
      ;;
    -f | --targets)
      if [[ -z "${2:-}" ]]; then
        err "option ${1} requires a file path"
        exit 1
      fi
      TARGETS_FILE="$2"
      shift 2
      ;;
    *)
      err "unknown option: $1"
      usage >&2
      exit 1
      ;;
  esac
done

sanitize_flat() {
  printf '%s' "$1" | sed 's|[^[:alnum:]._-]|_|g' | tr -s '_'
}

require_cmds() {
  local missing=()
  local c
  for c in gh jq zip unzip; do
    command -v "$c" >/dev/null 2>&1 || missing+=("$c")
  done
  if [[ ${#missing[@]} -gt 0 ]]; then
    err "missing required command(s): ${missing[*]}"
    exit 1
  fi
}
require_cmds

#################################
## Commonly Adjusted Variables ##
#################################

USER_SET_REPO="${REPO:+1}"
USER_SET_WORKFLOW="${WORKFLOW:+1}"
REPO="${REPO:-stolostron/governance-policy-framework}"
WORKFLOW="${WORKFLOW:-GRC Integration Test}"

if [[ -z "${DATELIMIT:-}" ]]; then
  if date -d '30 days ago' +'%Y-%m-%d' >/dev/null 2>&1; then
    DATELIMIT=$(date -d '30 days ago' +'%Y-%m-%d')
  else
    err "GNU date not found; set DATELIMIT=YYYY-MM-DD (e.g. DATELIMIT=2025-03-17)"
    exit 1
  fi
fi

# Max workflow runs to list (newest first).
RUN_LIMIT="${RUN_LIMIT:-300}"

# DRYRUN=1 / true / yes: print gh download commands only; otherwise perform downloads.
DRYRUN="${DRYRUN:-}"
case "${DRYRUN,,}" in
  1 | true | yes) DRYRUN_ACTIVE=1 ;;
  *) DRYRUN_ACTIVE=0 ;;
esac

# Seconds to sleep between each consecutive download. Helps avoid rate limiting errors.
DOWNLOAD_DELAY_SEC="${DOWNLOAD_DELAY_SEC:-1}"

readonly ARTIFACTS_LIST_FILE="artifacts-list.json"

# Base directory for REPORTS_PATH when using --targets (each row appends /repo/workflow).
TARGETS_REPORT_BASE="${TARGETS_REPORT_BASE:-${PWD}/test-output}"

# Split flattened XML into multiple zip archives when their combined uncompressed size would exceed this.
ZIP_MAX_UNCOMPRESSED_BYTES="${ZIP_MAX_UNCOMPRESSED_BYTES:-$((25 * 1024 * 1024))}"

# Keeps completed runs that are not cancelled or skipped (includes success and failure
# for flaky-test analysis).
# shellcheck disable=SC2016
readonly RUNS_JQ_FILTER='[.[] | select(
  .status == "completed"
  and .conclusion != "cancelled"
  and .conclusion != "skipped"
)]'

#################
## Main Script ##
#################

TMPDIR_WORK=$(mktemp -d)
trap 'rm -rf "${TMPDIR_WORK}"' EXIT

# Per-artifact download (API + unzip) for runs with attempt > 1 so same-named
# artifacts from different attempts do not overwrite on disk.
# Writes ARTIFACTS_LIST_FILE into dest_root: merged pages, unique_by(.id).
# Optional third argument: path to a temp file; failure lines are appended with >> and shown at the end
# of gather_test_reports. When set, per-artifact zip/unzip errors are logged there and the loop continues.
# Returns: 0 = success (possibly with logged per-artifact failures), 1 = no artifacts,
# 2 = failed to list artifacts for the run.
download_artifacts_by_id() {
  local db_id="$1"
  local dest_root="$2"
  local list_path="${dest_root}/${ARTIFACTS_LIST_FILE}"
  local failure_log_file="${3:-}"

  mkdir -p "${dest_root}"
  if ! gh api --paginate "repos/${REPO}/actions/runs/${db_id}/artifacts" \
    | jq -s '[.[] | .artifacts[]?] | unique_by(.id)' > "${list_path}"; then
    err "gh api or jq failed while listing artifacts for run ${db_id}"
    if [[ -n "${failure_log_file}" ]]; then
      echo "run ${db_id} (multi-attempt): failed to list or parse artifacts from API" >> "${failure_log_file}"
    fi
    return 2
  fi

  local artifact_total
  artifact_total=$(jq 'length' "${list_path}")

  if [[ "${artifact_total}" -eq 0 ]]; then
    err "No artifacts for run ${db_id} (skipped or upload failed?); skipping"
    return 1
  fi

  local a_idx=0
  while IFS=$'\t' read -r artifact_id artifact_name; do
    [[ -z "${artifact_id}" ]] && continue
    a_idx=$((a_idx + 1))
    local name_flat
    name_flat=$(sanitize_flat "${artifact_name}")
    local subdir="${dest_root}/artifact-${artifact_id}-${name_flat}"
    mkdir -p "${subdir}"
    local zip_path="${dest_root}/.artifact-${artifact_id}.zip"

    echo "  (multi-attempt) artifact ${artifact_id} (${a_idx}/${artifact_total}) name=${artifact_name} -> ${subdir}"
    if ! gh api "repos/${REPO}/actions/artifacts/${artifact_id}/zip" > "${zip_path}"; then
      rm -f "${zip_path}"
      if [[ -n "${failure_log_file}" ]]; then
        echo "run ${db_id} (multi-attempt): gh api failed to download zip for artifact id ${artifact_id} (${artifact_name})" >> "${failure_log_file}"
        continue
      fi
      err "gh api failed downloading zip for artifact ${artifact_id} (run ${db_id})"
      return 2
    fi

    if ! unzip -oq "${zip_path}" -d "${subdir}"; then
      rm -f "${zip_path}"
      if [[ -n "${failure_log_file}" ]]; then
        echo "run ${db_id} (multi-attempt): unzip failed for artifact id ${artifact_id} (${artifact_name})" >> "${failure_log_file}"
        continue
      fi
      err "unzip failed for artifact ${artifact_id} (run ${db_id})"
      return 2
    fi
    rm -f "${zip_path}"

    if [[ "${DOWNLOAD_DELAY_SEC}" != "0" && "${a_idx}" -lt "${artifact_total}" ]]; then
      sleep "${DOWNLOAD_DELAY_SEC}"
    fi
  done < <(jq -r '.[] | [.id, .name] | @tsv' "${list_path}")
  return 0
}

# Flatten *.xml from raw/ into REPORTS_PATH with filenames that encode each file's
# path under raw/. Slashes become underscores; spaces and other awkward characters
# become underscores too, leaving only alphanumerics, dots, hyphens, and underscores
# (portable for most import tools), e.g.
#   raw/12345/artifact-99-name/report.xml -> 12345_artifact-99-name_report.xml
flatten_xml_reports() {
  local raw_base="${REPORTS_PATH}/raw"
  if [[ ! -d "${raw_base}" ]]; then
    return 0
  fi
  local source_xml_path relative_path flat_basename
  while IFS= read -r -d '' source_xml_path; do
    relative_path="${source_xml_path#"${raw_base}/"}"
    flat_basename=$(sanitize_flat "${relative_path}")
    cp -- "${source_xml_path}" "${REPORTS_PATH}/${flat_basename}"
  done < <(find "${raw_base}" -type f -name '*.xml' -print0 2>/dev/null)
}

# Collect top-level *.xml under REPORTS_PATH, split them into zip archives whose
# uncompressed total does not exceed ZIP_MAX_UNCOMPRESSED_BYTES, then remove the
# loose XML copies. Uses runs.json for the date range in archive filenames.
# Arguments: $1 = filtered_count (number of runs in runs.json, used for date fallback).
archive_xml_reports() {
  local filtered_count="$1"

  local -a flat_xml_files=()
  local top_level_xml_path
  while IFS= read -r -d '' top_level_xml_path; do
    flat_xml_files+=("${top_level_xml_path}")
  done < <(find "${REPORTS_PATH}" -maxdepth 1 -type f -name '*.xml' -print0 2>/dev/null)

  if [[ ${#flat_xml_files[@]} -eq 0 ]]; then
    echo "No flattened XML files; skipping archive."
    return 0
  fi

  local date_min date_max range_part archive_stem repo_wf_safe today
  local max_uncompressed_bytes="${ZIP_MAX_UNCOMPRESSED_BYTES}"
  today="$(date +'%Y-%m-%d')"
  if [[ "${filtered_count}" -eq 0 ]]; then
    date_min="${DATELIMIT}"
    date_max="${today}"
  else
    date_min=$(jq -r '[.[].createdAt | .[0:10]] | min' "${REPORTS_PATH}/runs.json")
    date_max=$(jq -r '[.[].createdAt | .[0:10]] | max' "${REPORTS_PATH}/runs.json")
    # jq emits "null" if the array is empty or timestamps are missing; fall back like filtered_count==0.
    if [[ "${date_min}" == "null" || -z "${date_min}" || "${date_max}" == "null" || -z "${date_max}" ]]; then
      date_min="${DATELIMIT}"
      date_max="${today}"
    fi
  fi
  if [[ "${date_min}" == "${date_max}" ]]; then
    range_part="${date_min}"
  else
    range_part="${date_min}_to_${date_max}"
  fi
  repo_wf_safe=$(sanitize_flat "${REPO}_${WORKFLOW}")
  archive_stem="${repo_wf_safe}_${range_part}"

  # Remove prior zip(s) for this stem so reruns do not leave stale _part*.zip files beside new ones.
  shopt -s nullglob
  rm -f -- "${REPORTS_PATH}/${archive_stem}.zip" "${REPORTS_PATH}/${archive_stem}"_part*.zip
  shopt -u nullglob

  # --- Partition XML files into batches (greedy by total uncompressed size) ---
  # Sort for stable, reproducible splits. Walk files in order; accumulate into current_batch_files
  # until adding the next file would push current_batch_bytes over max_uncompressed_bytes, then
  # flush NUL-separated paths to batch_list_dir/batch.<batch_index> and start a new batch.
  # Files larger than the limit get their own batch (warning printed; that zip may exceed the cap).
  local -a sorted_xml_paths=()
  mapfile -t sorted_xml_paths < <(printf '%s\n' "${flat_xml_files[@]}" | sort)

  local batch_list_dir="${TMPDIR_WORK}/batches"
  rm -rf "${batch_list_dir}"
  mkdir -p "${batch_list_dir}"
  local batch_index=1
  local -a current_batch_files=()
  local current_batch_bytes=0
  local flat_xml_path file_size

  # Write accumulated paths to batch_list_dir/batch.<n> (NUL-separated), bump batch_index, clear accumulator.
  # Mutates: batch_index, current_batch_files, current_batch_bytes
  flush_open_batch() {
    if [[ ${#current_batch_files[@]} -eq 0 ]]; then
      return 0
    fi
    printf '%s\0' "${current_batch_files[@]}" > "${batch_list_dir}/batch.${batch_index}"
    batch_index=$((batch_index + 1))
    current_batch_files=()
    current_batch_bytes=0
  }

  for flat_xml_path in "${sorted_xml_paths[@]}"; do
    file_size=$(wc -c < "${flat_xml_path}")
    if [[ "${file_size}" -gt "${max_uncompressed_bytes}" ]]; then
      flush_open_batch
      err "warning: ${flat_xml_path##*/} (${file_size} bytes) exceeds ZIP_MAX_UNCOMPRESSED_BYTES (${max_uncompressed_bytes}); archiving it alone"
      printf '%s\0' "${flat_xml_path}" > "${batch_list_dir}/batch.${batch_index}"
      batch_index=$((batch_index + 1))
      continue
    fi
    if [[ "${current_batch_bytes}" -gt 0 && $((current_batch_bytes + file_size)) -gt "${max_uncompressed_bytes}" ]]; then
      flush_open_batch
      current_batch_files=("${flat_xml_path}")
      current_batch_bytes=${file_size}
      continue
    fi
    current_batch_files+=("${flat_xml_path}")
    current_batch_bytes=$((current_batch_bytes + file_size))
  done

  # Flush the last batch.
  flush_open_batch

  # batch_index was incremented past the last batch; total_batches is the actual count.
  local total_batches=$((batch_index - 1))
  if [[ "${total_batches}" -eq 0 ]]; then
    err "internal error: no zip batches produced"
    exit 1
  fi

  # --- Write one .zip per batch; multi-batch names use _partNofM before .zip ---
  local zip_filename zip_path batch_list_file
  for (( b=1; b<=total_batches; b++ )); do
    batch_list_file="${batch_list_dir}/batch.${b}"
    if [[ "${total_batches}" -eq 1 ]]; then
      zip_filename="${archive_stem}.zip"
    else
      zip_filename="${archive_stem}_part${b}of${total_batches}.zip"
    fi
    zip_path="${REPORTS_PATH}/${zip_filename}"
    if [[ ! -s "${batch_list_file}" ]]; then
      err "internal error: empty batch file ${batch_list_file}"
      exit 1
    fi
    # -j: store only basenames inside the archive. Use -@ so stdin supplies paths (avoids ARG_MAX if
    # there are many small XML files in one batch). Paths must not contain newlines.
    if ! tr '\0' '\n' < "${batch_list_file}" | zip -q -j "${zip_path}" -@; then
      err "zip failed for ${zip_path}"
      exit 1
    fi
    echo "Wrote archive: ${zip_path}"
  done
  rm -f -- "${flat_xml_files[@]}"
  echo "Removed flattened XML copies from ${REPORTS_PATH}"
}

gather_test_reports() {
  mkdir -p "${REPORTS_PATH}"

  # List runs: --status completed avoids in-flight rows; conclusion is filtered in jq.
  # See: https://docs.github.com/en/rest/actions/workflow-runs#list-workflow-runs-for-a-repository
  gh run list \
    --repo "${REPO}" \
    --workflow "${WORKFLOW}" \
    --created ">=${DATELIMIT}" \
    --status completed \
    --json createdAt,databaseId,number,url,status,conclusion,attempt,displayTitle \
    --limit "${RUN_LIMIT}" \
    | jq "${RUNS_JQ_FILTER}" \
    > "${REPORTS_PATH}/runs.json"

  local filtered_count
  filtered_count=$(jq 'length' "${REPORTS_PATH}/runs.json")
  echo "Found ${filtered_count} runs of \"${WORKFLOW}\" for ${REPO} (after filtering skipped and cancelled runs)"

  local run_count=0
  local total_runs=${filtered_count}
  local db_id attempt dest_root dl_rc
  local download_failure_log=""
  if [[ "${DRYRUN_ACTIVE}" -eq 0 ]]; then
    download_failure_log="${TMPDIR_WORK}/download-failures.log"
    : > "${download_failure_log}"
  fi

  while IFS=$'\t' read -r db_id attempt; do
    [[ -z "${db_id}" ]] && continue
    attempt=${attempt:-1}
    run_count=$((run_count + 1))
    dest_root="${REPORTS_PATH}/raw/${db_id}"

    if [[ "${attempt}" -le 1 ]]; then
      # Single attempt: one gh invocation; artifacts extracted under dest_root by name.
      echo "Run ${run_count}/${total_runs} databaseId=${db_id} attempt=${attempt} (simple download)"
      if [[ "${DRYRUN_ACTIVE}" -eq 1 ]]; then
        echo gh run download "${db_id}" --repo "${REPO}" --dir "${dest_root}"
      else
        mkdir -p "${dest_root}"
        if ! gh run download "${db_id}" --repo "${REPO}" --dir "${dest_root}"; then
          echo "run ${db_id} (simple download): gh run download failed" >> "${download_failure_log}"
        fi
      fi
    else
      # Multiple attempts: same artifact names may repeat; use per-id paths.
      echo "Run ${run_count}/${total_runs} databaseId=${db_id} attempt=${attempt} (multi-attempt download)"
      if [[ "${DRYRUN_ACTIVE}" -eq 1 ]]; then
        # Beware: the command printed here might not match what is in download_artifacts_by_id in the future.
        echo "gh api --paginate \"repos/${REPO}/actions/runs/${db_id}/artifacts\" \\"
        echo "  | jq -s '[.[] | .artifacts[]?] | unique_by(.id)' > \"${dest_root}/${ARTIFACTS_LIST_FILE}\""
        echo "# then: jq -r '.[] | [.id,.name] | @tsv' < that file; gh api …/artifacts/<id>/zip per row"
      else
        mkdir -p "${dest_root}"
        dl_rc=0
        download_artifacts_by_id "${db_id}" "${dest_root}" "${download_failure_log}" || dl_rc=$?
        if [[ "${dl_rc}" -eq 1 ]]; then
          : # No artifacts; message already printed inside download_artifacts_by_id
        fi
        # dl_rc 2 (could not list artifacts) is also appended to download_failure_log; run continues.
      fi
    fi

    if [[ "${DRYRUN_ACTIVE}" -eq 0 && "${DOWNLOAD_DELAY_SEC}" != "0" && "${run_count}" -lt "${total_runs}" ]]; then
      sleep "${DOWNLOAD_DELAY_SEC}"
    fi
  done < <(jq -r '.[] | [.databaseId, (.attempt // 1)] | @tsv' "${REPORTS_PATH}/runs.json")

  if [[ "${DRYRUN_ACTIVE}" -eq 0 ]]; then
    echo "Downloads complete."
    if [[ -n "${download_failure_log}" && -s "${download_failure_log}" ]]; then
      echo "" >&2
      echo "=== Download failures (see above for successful runs) ===" >&2
      cat "${download_failure_log}" >&2
    fi
  else
    echo "Dry run complete (DRYRUN is set; no artifacts were downloaded)."
  fi

  flatten_xml_reports
  archive_xml_reports "${filtered_count}"
}

# Actually run `gather_test_reports` for each target in TARGETS_FILE (if supplied),
# or the given REPO and WORKFLOW.
if [[ -n "${TARGETS_FILE}" ]]; then
  if [[ ! -f "${TARGETS_FILE}" ]]; then
    err "targets file not found: ${TARGETS_FILE}"
    exit 1
  fi
  if [[ -n "${REPORTS_PATH:-}" ]]; then
    err "warning: REPORTS_PATH is ignored with --targets (output is TARGETS_REPORT_BASE/<repo>/<workflow>)"
  fi
  if [[ -n "${USER_SET_REPO}" ]]; then
    err "warning: REPO is ignored with --targets (repo comes from each line of the targets file)"
  fi
  if [[ -n "${USER_SET_WORKFLOW}" ]]; then
    err "warning: WORKFLOW is ignored with --targets (workflow comes from each line of the targets file)"
  fi
  # Each non-comment line is tab-separated: owner/repo, workflow name, optional extra fields.
  # IFS=$'\t' splits on tabs only; _ collects a third column and beyond so names with spaces
  # stay in target_workflow. The trailing "|| [[ -n ... ]]" handles a final line with no newline.
  while IFS=$'\t' read -r target_repo target_workflow _ || [[ -n "${target_repo}" ]]; do
    [[ -z "${target_repo}" || "${target_repo}" =~ ^# ]] && continue

    REPO="${target_repo}"
    WORKFLOW="${target_workflow}"
    REPORTS_PATH="${TARGETS_REPORT_BASE}/${target_repo}/$(sanitize_flat "${target_workflow}")"
    echo ""
    echo "=== ${REPO} / ${WORKFLOW} -> ${REPORTS_PATH} ==="
    gather_test_reports
  done < "${TARGETS_FILE}"
else
  REPORTS_PATH="${REPORTS_PATH:-${PWD}/${REPO}/$(sanitize_flat "${WORKFLOW}")}"
  gather_test_reports
fi
